module ARQ_System(  
    input clk,  
    input rst,  
    input [7:0] data_in,  
    input error_in,  
    output reg [7:0] data_out,  
    output reg ack  
);  
    reg [7:0] parity_data;  
    reg error_detected;  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            parity_data <= 8'b0;  
            error_detected <= 1'b0;  
            ack <= 1'b0;  
        end else begin  
            parity_data <= data_in;  
            error_detected <= error_in;  
            if (!error_detected) begin  
                data_out <= parity_data;  
                ack <= 1'b1;  
            end else begin  
                ack <= 1'b0;  
            end  
        end  
    end  
endmodule
